    app.use('*', languageDetector({
        supportedLanguages: ['en', 'ja'],
        fallbackLanguage: 'en'
    }))
    app.get('/', (c) => c.text(String(c.get('language'))))

    const run = async (segments: number) => {
        const v = 'a;'.repeat(segments) + '"'
        const req = new Request('http://localhost/', {
            headers: {
                'accept-language': v
